import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int N = sc.nextInt();
        int L = sc.nextInt();
        int[] x = new int[N];
        int[] y = new int[N];
        int[] c = new int[N];
        for (int i = 0; i < N; i++) {
            x[i] = sc.nextInt();
            y[i] = sc.nextInt();
            c[i] = sc.nextInt();
        }
        int max_sum = Integer.MIN_VALUE;
        int min_side = Integer.MAX_VALUE;
        for (int side = 1; side <= L; side++) {
            for (int i = 0; i < N; i++) {
                int sum = 0;
                for (int j = 0; j < N; j++) {
                    if (x[j] >= x[i] && x[j] < x[i] + side && y[j] >= y[i] && y[j] < y[i] + side) {
                        sum += c[j];
                    }
                }
                if (sum > max_sum) {
                    max_sum = sum;
                    min_side = side;
                } else if (sum == max_sum && side < min_side) {
                    min_side = side;
                }
            }
        }
        System.out.println(max_sum + " " + min_side);
